// Get uploaded image binary data
const items = $input.all();
const first = items[0];
const binary = first.binary;

// Find the image field
const imgKey = Object.keys(binary).find(k => k !== 'data' && (binary[k].mimeType?.startsWith('image/')))
  || Object.keys(binary).find(k => binary[k].mimeType?.startsWith('image/'))
  || Object.keys(binary)[0];

const img = binary[imgKey];
if (!img) throw new Error('No image found in webhook payload');

return items.map(item => ({
  json: {
    binaryKey: imgKey,
    mimeType: img.mimeType || 'image/jpeg'
  },
  binary: item.binary
}));

// ⚠️ GANTI NODE DIATAS DENGAN:
// 1. Tambah node "Google Gemini Chat Model" (bukan agent)
// 2. Connect credential Gemini API
// 3. Set model: gemini-2.5-flash
// 4. Prompt: system message di code node ini
//
// Untuk sekarang, parse Gemini response dari node LLM
const response = $input.first().json;
let text = response.output || response.text || '';

// Bersihkan markdown fences
text = text.replace(/```json\n?|```/g, '').trim();

let data = {};
try {
  data = JSON.parse(text);
} catch(e) {
  // Coba ekstrak JSON dari text
  const m = text.match(/\{[\s\S]*\}/);
  if (m) try { data = JSON.parse(m[0]); } catch(e2) {}
}

const isbn = (data.isbn || '').replace(/[^0-9Xx]/g, '');

return {
  isbn: isbn || null,
  title: data.title || null,
  author: data.author || null,
  publisher: data.publisher || null,
  category: data.category || null
};

const data = $input.first().json;
const isbn = data.isbn;
const title = data.title;

// Get front cover from webhook
let coverUrl = null;

return {
  _gemini: data,
  apiCalls: [
    isbn ? { name: 'google', url: `https://www.googleapis.com/books/v1/volumes?q=isbn:${isbn}` } : null,
    isbn ? { name: 'openlib', url: `https://openlibrary.org/isbn/${isbn}.json` } : null,
    (!isbn && title) ? { name: 'google_title', url: `https://www.googleapis.com/books/v1/volumes?q=${encodeURIComponent('intitle:' + title)}&maxResults=1` } : null,
    (!isbn && title) ? { name: 'openlib_title', url: `https://openlibrary.org/search.json?title=${encodeURIComponent(title)}&limit=1` } : null,
  ].filter(Boolean)
};

// Merge: Gemini + Google Books + OpenLibrary
const all = $input.all();
const gemini = all[0]?.json?._gemini || {};
const googleRaw = all.find(i => i.json?.items && !i.json?._gemini && !i.json?.apiCalls)?.json;
const olRaw = all.find(i => (i.json?.title || i.json?.publishers) && !i.json?._gemini)?.json;
const olSearch = all.find(i => i.json?.docs && !i.json?._gemini)?.json;

// Parse Google
let g = {};
if (googleRaw?.items?.length) {
  const vi = googleRaw.items[0].volumeInfo || {};
  g = {
    title: vi.title, author: (vi.authors||[]).join(', '),
    publisher: vi.publisher, year: vi.publishedDate ? parseInt(vi.publishedDate.substring(0,4)) : null,
    desc: vi.description, category: vi.categories?.[0],
    cover: vi.imageLinks?.thumbnail?.replace('http:','https:'), lang: vi.language
  };
}

// Parse OpenLibrary direct
let o = {};
if (olRaw?.title) {
  o = {
    title: olRaw.title, author: olRaw.authors?.map(a=>a.name||a).join(', '),
    publisher: olRaw.publishers?.[0], year: olRaw.publish_date ? parseInt(olRaw.publish_date.substring(0,4)) : null,
    cover: olRaw.covers?.[0] ? `https://covers.openlibrary.org/b/id/${olRaw.covers[0]}-M.jpg` : null
  };
}

// Parse OpenLibrary search
if (olSearch?.docs?.length) {
  const d = olSearch.docs[0];
  o = {
    title: d.title || o.title, author: d.author_name?.join(', ') || o.author,
    publisher: d.publisher?.[0] || o.publisher, year: d.first_publish_year || o.year,
    cover: d.cover_i ? `https://covers.openlibrary.org/b/id/${d.cover_i}-M.jpg` : o.cover
  };
}

const pick = (a,b,c) => a || b || c || null;

return {
  found: true,
  book: {
    title: pick(g.title, o.title, gemini.title) || '',
    author: pick(g.author, o.author, gemini.author) || '',
    isbn: gemini.isbn || '',
    publisher: pick(g.publisher, o.publisher, gemini.publisher) || '',
    published_year: pick(g.year, o.year, null),
    description: g.desc || '',
    category: pick(g.category, null, gemini.category) || '',
    cover_url: pick(g.cover, o.cover, null) || ''
  },
  sources: { google: !!Object.keys(g).filter(k=>g[k]).length, openlibrary: !!Object.keys(o).filter(k=>o[k]).length, gemini: true }
};
